public class TestRunner {
    static int passed = 0;
    static int failed = 0;

    public static void main(String[] args) {

        // ── Can we create a Potion with no-arg constructor? ──
        try {
            Potion p = new Potion();
            check("Potion() creates an object",
                  "true", String.valueOf(p != null));
        } catch (Exception e) { fail("Potion() constructor", e); }

        // ── Fields are accessible (not private) ──
        try {
            Potion p = new Potion();
            p.name = "Health Potion";
            p.healingAmount = 50;
            p.price = 10;
            check("Field name is settable",
                  "Health Potion", p.name);
        } catch (Exception e) { fail("Field name", e); }

        try {
            Potion p = new Potion();
            p.healingAmount = 75;
            check("Field healingAmount is settable",
                  "75", String.valueOf(p.healingAmount));
        } catch (Exception e) { fail("Field healingAmount", e); }

        try {
            Potion p = new Potion();
            p.price = 20;
            check("Field price is settable",
                  "20", String.valueOf(p.price));
        } catch (Exception e) { fail("Field price", e); }

        // ── describe() returns correct string ──
        try {
            Potion p = new Potion();
            p.name = "Health Potion";
            p.healingAmount = 50;
            p.price = 10;
            check("describe() — Health Potion",
                  "Health Potion restores 50 health and costs 10 gold.",
                  p.describe());
        } catch (Exception e) { fail("describe() — Health Potion", e); }

        try {
            Potion p = new Potion();
            p.name = "Mana Elixir";
            p.healingAmount = 30;
            p.price = 15;
            check("describe() — Mana Elixir",
                  "Mana Elixir restores 30 health and costs 15 gold.",
                  p.describe());
        } catch (Exception e) { fail("describe() — Mana Elixir", e); }

        // ── Two potions have independent fields ──
        try {
            Potion a = new Potion();
            a.name = "Potion A";
            a.healingAmount = 10;
            a.price = 5;

            Potion b = new Potion();
            b.name = "Potion B";
            b.healingAmount = 99;
            b.price = 50;

            boolean independent = !a.name.equals(b.name)
                               && a.healingAmount != b.healingAmount;
            check("Two Potions hold independent data",
                  "true", String.valueOf(independent));
        } catch (Exception e) { fail("Independent instances", e); }

        // ── describe() uses the object's own fields (not hard-coded) ──
        try {
            Potion p = new Potion();
            p.name = "Phoenix Down";
            p.healingAmount = 999;
            p.price = 200;
            check("describe() uses own fields",
                  "Phoenix Down restores 999 health and costs 200 gold.",
                  p.describe());
        } catch (Exception e) { fail("describe() uses own fields", e); }
    }

    static void check(String label, String expected, String actual) {
        if (expected.equals(actual)) {
            System.out.println("PASS: " + label); passed++;
        } else {
            System.out.println("FAIL: " + label
                + " \u2014 expected \"" + expected
                + "\" but got \"" + actual + "\""); failed++;
        }
    }
    static void fail(String label, Exception e) {
        System.out.println("FAIL: " + label + " \u2014 " + e.getMessage()); failed++;
    }
}
